var ga = new GlideAggregate('incident');
ga.addQuery('active', true);
ga.addQuery('priority', 1);
ga.addAggregate('COUNT');
ga.groupBy('assignment_group');
ga.query();
while (ga.next()) {
  gs.print(ga.getDisplayValue('assignment_group') + ' -> ' + ga.getAggregate('COUNT'));
}

var PriorityUtils = Class.create();
PriorityUtils.prototype = {
  initialize: function() {},
  getPriority: function(impact, urgency) {
    var score = parseInt(impact, 10) + parseInt(urgency, 10);
    if (score <= 2) return 1;
    if (score === 3) return 2;
    if (score === 4) return 3;
    return 4;
  },
  type: 'PriorityUtils'
};

var ga = new GlideAggregate('cmdb_ci');
ga.addAggregate('COUNT');
ga.groupBy('name');
ga.groupBy('sys_class_name');
ga.query();
while (ga.next()) {
  var count = parseInt(ga.getAggregate('COUNT'), 10);
  if (count > 1) {
    gs.print(ga.getValue('name') + ' | ' + ga.getDisplayValue('sys_class_name') + ' | ' + count);
  }
}

var parentServiceId = 'PUT_PARENT_SERVICE_SYS_ID_HERE';
var rel = new GlideRecord('cmdb_rel_ci');
rel.addQuery('parent', parentServiceId);
rel.query();
while (rel.next()) {
  gs.print(rel.child.getDisplayValue() + ' [' + rel.type.getDisplayValue() + ']');
}

var ga = new GlideAggregate('cmdb_ci');
ga.addNotNullQuery('discovery_source');
ga.addAggregate('COUNT');
ga.groupBy('discovery_source');
ga.query();
while (ga.next()) {
  gs.print(ga.getValue('discovery_source') + ' -> ' + ga.getAggregate('COUNT'));
}

var mid = new GlideRecord('ecc_agent');
mid.query();
while (mid.next()) {
  gs.print(mid.name + ' | status=' + mid.status + ' | validated=' + mid.validated);
}

var RiskScoringUtils = Class.create();
RiskScoringUtils.prototype = {
  initialize: function() {},
  getRating: function(impact, likelihood) {
    var score = parseInt(impact, 10) * parseInt(likelihood, 10);
    if (score >= 16) return 'Critical';
    if (score >= 9) return 'High';
    if (score >= 4) return 'Moderate';
    return 'Low';
  },
  type: 'RiskScoringUtils'
};

var gr = new GlideRecord('task');
gr.addQuery('state', '!=', 3);
gr.addQuery('due_date', '<=', gs.daysAgoEnd(-2));
gr.query();
while (gr.next()) {
  gs.eventQueue('grc.attestation.reminder', gr, gr.getUniqueValue(), gr.assigned_to);
}

var VulnerabilityPriorityUtils = Class.create();
VulnerabilityPriorityUtils.prototype = {
  initialize: function() {},
  getPriority: function(exploitability, criticality) {
    var score = parseInt(exploitability, 10) + parseInt(criticality, 10);
    if (score >= 8) return 'P1';
    if (score >= 6) return 'P2';
    if (score >= 4) return 'P3';
    return 'P4';
  },
  type: 'VulnerabilityPriorityUtils'
};

var ga = new GlideAggregate('sn_vul_vulnerable_item');
ga.addQuery('state', '!=', 'closed');
ga.addAggregate('COUNT');
ga.groupBy('assignment_group');
ga.query();
while (ga.next()) {
  gs.print(ga.getDisplayValue('assignment_group') + ' -> ' + ga.getAggregate('COUNT'));
}

var gr = new GlideRecord('alm_hardware');
gr.addNullQuery('assigned_to');
gr.addQuery('install_status', 'in_use');
gr.query();
while (gr.next()) {
  gs.print(gr.asset_tag + ' | ' + gr.getDisplayValue('model'));
}

