var SAMReclamationUtils = Class.create();
SAMReclamationUtils.prototype = {
  initialize: function() {},
  isCandidate: function(daysSinceUse, threshold) {
    return parseInt(daysSinceUse, 10) >= parseInt(threshold, 10);
  },
  type: 'SAMReclamationUtils'
};

var PublisherNormalizationUtils = Class.create();
PublisherNormalizationUtils.prototype = {
  initialize: function() {},
  normalize: function(name) {
    var map = {
      'microsoft corporation': 'Microsoft',
      'microsoft corp.': 'Microsoft',
      'adobe systems': 'Adobe',
      'adobe inc.': 'Adobe'
    };
    var key = (name || '').toString().toLowerCase();
    return map[key] || name;
  },
  type: 'PublisherNormalizationUtils'
};
